using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;

namespace YourProjectName.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FileUploadController : ControllerBase
    {
        [HttpPost("upload-avatar")]
        public IActionResult UploadAvatar(IFormFile file)
        {
            if (file == null || file.Length == 0) return BadRequest();

            var allowedMimeTypes = new[] { "image/jpeg", "image/png" }; // Adjust this according to your needs
            if (!allowedMimeTypes.Contains(file.ContentType)) return BadRequest("Invalid file type");

            string fileName = Path.Combine("uploads", Guid.NewGuid().ToString() + Path.GetExtension(file.FileName));
            var directory = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot/uploads");
            Directory.CreateDirectory(directory);
            using (var stream = new FileStream(Path.Combine(directory, fileName), FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok(Url.Content($"/uploads/{fileName}"));
        }

        [HttpPost("upload-document")]
        public IActionResult UploadDocument(IFormFile file)
        {
            if (file == null || file.Length == 0) return BadRequest();

            var allowedMimeTypes = new[] { "application/pdf", "application/vnd.openxmlformats-officedocument.wordprocessingml.document", "application/vnd.ms-excel" }; // Adjust this according to your needs
            if (!allowedMimeTypes.Contains(file.ContentType)) return BadRequest("Invalid file type");

            string fileName = Path.Combine("uploads", Guid.NewGuid().ToString() + Path.GetExtension(file.FileName));
            var directory = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot/uploads");
            Directory.CreateDirectory(directory);
            using (var stream = new FileStream(Path.Combine(directory, fileName), FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok(Url.Content($"/uploads/{fileName}"));
        }
    }
